import './App.css';
import { ChangeEvent, useState, useEffect } from 'react';
import { PlayModule } from './PlayModule';
import { useAppDispatch, useAppSelector, bootFile } from "./Actions";

function Stats() {
  const [stats, setStats] = useState({ fps: 0 });
  useEffect(() => {
    const timer = setInterval(() => {
      const frames = PlayModule.getFrames();
      PlayModule.clearStats();
      setStats({ fps: frames }); 
    }, 1000);
    return () => {
      clearInterval(timer);
    };
  }, [stats]);
  return (
    <span className="stats">{stats.fps} f/s</span>
  )
}

// True when embedded as a child iframe (e.g. the CARTRIDGE site), false when
// run standalone. Embedded mode hides the manual file picker and instead
// takes the game via postMessage from the parent page.
const embedded = window.self !== window.top;

function App() {
  const state = useAppSelector((state) => state.play);
  const dispatch = useAppDispatch();
  const handleChange = function(event : ChangeEvent<HTMLInputElement>) {
    if(event.target && event.target.files && event.target.files.length !== 0) {
      let file = event.target.files[0];
      dispatch(bootFile(file));
    }
  }

  // Parent page hands the game over as a postMessage instead of a file input
  // pick, since this app is loaded in an iframe with its own bootFile action
  // already wired up to accept a File object directly.
  useEffect(() => {
    if (!embedded) return;
    const handler = (event: MessageEvent) => {
      const data = event.data;
      if (!data || data.type !== 'load-rom') return;
      // The parent sends the stored Blob/File directly (structured-cloned,
      // not copied) since game images can be multi-gigabyte and
      // DiscImageDevice reads it lazily via slice(). Wrap it in a File if it
      // arrived as a bare Blob (e.g. lost its File-ness round-tripping
      // through IndexedDB) so bootFile has a name to detect the extension.
      const raw = data.file;
      const name = data.name || (raw && raw.name) || 'game.iso';
      const file = raw instanceof File ? raw : new File([raw], name);
      dispatch(bootFile(file));
    };
    window.addEventListener('message', handler);
    return () => window.removeEventListener('message', handler);
  }, [dispatch]);

  // Tell the parent page once the WASM module has finished initializing and
  // is ready to receive a game, mirroring the ready handshake the parent
  // already uses for its other emulator cores.
  useEffect(() => {
    if (embedded && state.value === "initialized") {
      window.parent.postMessage({ type: 'iframe-ready' }, '*');
    }
  }, [state.value]);

  console.log(state.value);
  if(PlayModule === null) {
    return (
      <div>Loading...</div>
    );
  } else {
    return (
      <div>
        {!embedded && <input type="file" onChange={handleChange}/>}
        <Stats />
        <span className="version">
          {`Version: ${process.env.REACT_APP_VERSION}`}
        </span>
      </div>
    );
  }
}

export default App;
